// ============================================================
// كود n8n لمراقبة الاستهلاك والتاريخ
// الرصيد الأساسي: balance_egp | الاستهلاك: cost_egp
// لا يتم إرسال أي تنبيهات للعملاء الذين انتهت باقتهم بالفعل
// Mode: Run Once for All Items
// ============================================================

// ============== المتغيرات ==============
const DAYS_BEFORE_END = [5, 2, 0];   // تنبيهات الأيام
const TODAY = new Date();            // تاريخ اليوم الفعلي

// أسماء الحقول في الداتا
const FIELD_BUSINESS_ID = "business_id";
const FIELD_PERIOD_END = "period_end";
const FIELD_BASE_BALANCE = "balance_egp";  // الرصيد الأساسي
const FIELD_COST = "cost_egp";             // التكلفة (الاستهلاك)

// ============== الدوال المساعدة ==============

// يحول نص "YYYY-MM-DD" إلى Date
function parseDate(dateStr) {
  const [year, month, day] = dateStr.split("-").map(Number);
  return new Date(year, month - 1, day);
}

// عدد الأيام الفاصلة بين تاريخين
function daysBetween(dateA, dateB) {
  const msPerDay = 1000 * 60 * 60 * 24;
  const a = new Date(dateA.getFullYear(), dateA.getMonth(), dateA.getDate());
  const b = new Date(dateB.getFullYear(), dateB.getMonth(), dateB.getDate());
  return Math.round((a - b) / msPerDay);
}

// دالة فحص وتنبيه الرصيد (90% و 100%)
function getBalanceAlertText(record) {
  const baseBalance = record[FIELD_BASE_BALANCE] || 0; 
  const costAmount = record[FIELD_COST] || 0;          

  if (baseBalance <= 0) return null;

  const remainingBalance = baseBalance - costAmount;
  const consumedPercent = (costAmount / baseBalance) * 100;

  if (remainingBalance <= 0 || consumedPercent >= 100) {
    return `تنبيه: لقد استهلكت 100% من رصيد باقتك الحالي. الرصيد المتبقي هو 0 ج.م، تم إيقاف الخدمة مؤقتاً، يُرجى إعادة الشحن فوراً لتفعيل الخدمة.`;
  }

  if (consumedPercent >= 90) {
    return `تنبيه: لقد استهلكت ${consumedPercent.toFixed(0)}% من رصيد باقتك. الرصيد المتبقي لديك هو ${remainingBalance.toFixed(2)} ج.م فقط، يُرجى الشحن قريباً لتجنب انقطاع الخدمة.`;
  }

  return null;
}

// تنبيه التاريخ (تم إزالة رسالة الانتهاء لأننا بنتجاهلهم)
function getDateAlertText(daysLeft, record) {
  if (DAYS_BEFORE_END.includes(daysLeft)) {
    if (daysLeft === 0) {
      return `اليوم هو آخر يوم في باقتك الحالية (تنتهي ${record[FIELD_PERIOD_END]})، سيتم إيقاف الخدمة تلقائياً خلال 4 أيام في حال لم يتم التجديد. يمكنك التجديد عبر لوحة التحكم الخاصة بك.`;
    }
    return `باقتك ستنتهي بعد ${daysLeft} ${daysLeft === 1 ? "يوم" : "أيام"} (بتاريخ ${record[FIELD_PERIOD_END]})، يُرجى التجديد في الوقت المناسب.`;
  }
  return null;
}

// ============== التنفيذ الرئيسي ==============

const records = items.map((item) => item.json);
const alertsByBusiness = {}; 

for (const record of records) {
  const businessId = record[FIELD_BUSINESS_ID];
  const periodEnd = parseDate(record[FIELD_PERIOD_END]);
  const daysLeft = daysBetween(periodEnd, TODAY);

  // === الشرط الجديد: تجاهل السجلات التي انتهت صلاحيتها ===
  if (daysLeft < 0) {
    continue; 
  }

  const balanceText = getBalanceAlertText(record);
  const dateText = getDateAlertText(daysLeft, record);

  if (!balanceText && !dateText) continue; 

  if (!alertsByBusiness[businessId]) {
    alertsByBusiness[businessId] = { parts: [], lastRecord: record };
  }

  if (balanceText) alertsByBusiness[businessId].parts.push(balanceText);
  if (dateText) alertsByBusiness[businessId].parts.push(dateText);

  alertsByBusiness[businessId].lastRecord = record; 
}

const outputItems = [];

for (const businessId of Object.keys(alertsByBusiness)) {
  const { parts, lastRecord } = alertsByBusiness[businessId];
  const uniqueParts = [...new Set(parts)];

  const message =
    `عزيزي العميل،\n` +
    uniqueParts.join("\n") +
    `\n\nشكراً لتعاملك معنا.`;

  outputItems.push({
    json: {
      business_id: businessId,
      message: message,
      alerts_count: uniqueParts.length,
      period_end: lastRecord[FIELD_PERIOD_END],
      base_balance_egp: lastRecord[FIELD_BASE_BALANCE],
      cost_egp: lastRecord[FIELD_COST]
    },
  });
}

return outputItems;
